package main

import (
    "log"
    "net/http"
)

func healthHandler(w http.ResponseWriter, r *http.Request) {
    w.WriteHeader(http.StatusOK)
    w.Write([]byte("OK"))
}

func main() {
    h := http.HandlerFunc(healthHandler)
    server := http.Server{
        Addr:    ":8001",
        Handler: h,
    }
    log.Fatal(server.ListenAndServe())
}
